// ansi-styles-shape: ANSI escape codes for terminal styling.
// Vendored equivalent, MIT, dependency-free.

const ESC = "[";

function code(open, close) {
    return {
        open: ESC + open + "m",
        close: ESC + close + "m",
    };
}

export const reset = code(0, 0);
export const bold = code(1, 22);
export const italic = code(3, 23);
export const underline = code(4, 24);

export const fg = {
    black: code(30, 39),
    red: code(31, 39),
    green: code(32, 39),
    yellow: code(33, 39),
    blue: code(34, 39),
    magenta: code(35, 39),
    cyan: code(36, 39),
    white: code(37, 39),
};

export const bg = {
    black: code(40, 49),
    red: code(41, 49),
    green: code(42, 49),
    yellow: code(43, 49),
};

export default { reset, bold, italic, underline, fg, bg };
